// SetWorld2d mirrors the Godot Viewport.set_world_2d method.
func (self *Viewport) SetWorld2d(world_2d *World2D) {
	var tmp_world_2d gdextension.ObjectPtr
	if world_2d != nil {
		tmp_world_2d = world_2d.Ptr()
	}

	args := [...]gdextension.TypePtr{
		gdextension.TypePtr(unsafe.Pointer(&tmp_world_2d)),
	}
	gdextension.CallMethodBindPtrCall(viewportMethodSetWorld2d(), self.Ptr(), args[:], nil)
}

// GetWorld2d mirrors the Godot Viewport.get_world_2d method.
func (self *Viewport) GetWorld2d() *World2D {
	var ret gdextension.ObjectPtr
	gdextension.CallMethodBindPtrCall(viewportMethodGetWorld2d(), self.Ptr(), nil, gdextension.TypePtr(unsafe.Pointer(&ret)))
	return World2DFromPtr(ret)
}

// FindWorld2d mirrors the Godot Viewport.find_world_2d method.
